def to_json_safe(
      %__MODULE__{
        direction_names: direction_names,
        direction_destinations: direction_destinations
      } = route
    ) do
  direction_destinations_value =
    if direction_destinations == :unknown do
      nil
    else
      %{"0" => direction_destinations[0], "1" => direction_destinations[1]}
    end

  %{
    Map.from_struct(route)
    | direction_names: %{"0" => direction_names[0], "1" => direction_names[1]},
      direction_destinations: direction_destinations_value
  }
end

